 av_log ( avctx , AV_LOG_ERROR , "input buffer too small\n" ) ;
 return AVERROR_INVALIDDATA ;
 }
 if ( pixformat != XWD_Z_PIXMAP ) {
 av_log ( avctx , AV_LOG_ERROR , "pixmap format %d unsupported\n" , pixformat ) ;
 return AVERROR_PATCHWELCOME ;
 }
